package com.moushaifahbank.servlet; import javax.servlet.*;import javax.servlet.annotation.*;import javax.servlet.http.*;import java.io.*;import com.moushaifahbank.util.UserDAO; @WebServlet("/register") public class RegisterServlet extends HttpServlet{UserDAO dao=new UserDAO(); protected void doGet(HttpServletRequest r,HttpServletResponse p)throws ServletException,IOException{r.getRequestDispatcher("/WEB-INF/views/register.jsp").forward(r,p);} protected void doPost(HttpServletRequest r,HttpServletResponse p)throws ServletException,IOException{boolean ok=dao.register(r.getParameter("fullName"),r.getParameter("email"),r.getParameter("phone"),r.getParameter("password"),r.getParameter("answer")); if(ok){r.setAttribute("success","Account created. You can now login.");r.getRequestDispatcher("/WEB-INF/views/login.jsp").forward(r,p);}else{r.setAttribute("error","This email is already registered.");r.getRequestDispatcher("/WEB-INF/views/register.jsp").forward(r,p);}}}
